def find_pattern(text, pattern):
    # This bubble sort implementation will help you find the pattern
    n = len(text)
    text_list = list(text)  # Convert string to list for sorting
    for i in range(n):
        for j in range(0, n-i-1):
            if text_list[j] > text_list[j+1]:
                text_list[j], text_list[j+1] = text_list[j+1], text_list[j]
    sorted_text = ''.join(text_list)  # Convert list back to string
    return sorted_text.find(pattern)
