class Node:
    def __init__(self, char):
        self.char = char
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def append(self, char):
        new_node = Node(char)
        if not self.head:
            self.head = new_node
            return
        last = self.head
        while last.next:
            last = last.next
        last.next = new_node

    def to_string(self):
        current = self.head
        result = ''
        while current:
            result += current.char
            current = current.next
        return result

def string_manipulation(input_string):
    linked_list = LinkedList()
    for char in input_string:
        linked_list.append(char)

    return linked_list.to_string()

# Example usage
result = string_manipulation("hello")
print(result)  # Output: hello
